#include <bits/stdc++.h>
using namespace std;
int n[130],s,ax=-1,in=INT_MAX;
string a;
bool zs(int s){
	if(s<2){
		return 0;
	}
	for(int i=2;i*i<=s;i++){
		if(s%i==0){
			return 0;
		}
	}
	return 1;
}
int main() {
	getline(cin,a);
	for(int i=0; i<a.size(); i++) {
		n[int(a[i])]++;
	}
	for(int i=0; i<130; i++) {
		if(n[i]!=0) {
			ax=max(n[i],ax);
			in=min(n[i],in);
		}
	}
	s=ax-in;
	if(zs(s)) {
		cout<<"Lucky Word\n";
		cout<<s;
	} else {
		cout<<"No Answer\n";
		cout<<0;
	}
	return 0;
}
